// frontend/src/pages/JS AIDashboard.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AIDashboard = () => {
  const [resumeText, setResumeText] = useState('');
  const [resumeCategory, setResumeCategory] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('checking');
  
  const token = localStorage.getItem('token');
  const BACKEND_URL = 'http://localhost:5000';
  const AI_API_URL = 'http://localhost:5001';

  useEffect(() => {
    checkAIStatus();
    loadUserResume();
  }, []);

  const checkAIStatus = async () => {
    try {
      const response = await axios.get(`${AI_API_URL}/health`);
      setAiStatus(response.data.status === 'AI Service Running' ? 'online' : 'offline');
    } catch (error) {
      setAiStatus('offline');
    }
  };

  const loadUserResume = async () => {
    setLoading(true);
    try {
      let resumeTextFromStorage = '';
      
      // Try to get from backend first
      try {
        const response = await axios.get(`${BACKEND_URL}/api/applications`, {
          headers: { 'x-auth-token': token }
        });
        if (response.data && response.data.length > 0) {
          resumeTextFromStorage = response.data[0].resumeText || '';
        }
      } catch (err) {
        console.log('Backend fetch failed, checking localStorage');
      }
      
      // Fallback to localStorage
      if (!resumeTextFromStorage) {
        resumeTextFromStorage = localStorage.getItem('userResume') || '';
      }
      
      setResumeText(resumeTextFromStorage);
      
      if (resumeTextFromStorage) {
        await analyzeResume(resumeTextFromStorage);
      } else {
        console.log('No resume found');
      }
    } catch (error) {
      console.error('Error loading resume:', error);
    }
    setLoading(false);
  };

  const analyzeResume = async (text) => {
    setLoading(true);
    try {
      // Get category prediction
      const categoryRes = await axios.post(`${AI_API_URL}/predict/category`, {
        resume_text: text
      });
      setResumeCategory(categoryRes.data.predicted_category);

      // Job recommendations based on resume
      const jobs = [
        { id: 1, title: 'Software Engineer', description: 'Python, Django, React, SQL, AWS, JavaScript' },
        { id: 2, title: 'Data Scientist', description: 'Python, Machine Learning, SQL, Pandas, NumPy, Statistics' },
        { id: 3, title: 'Full Stack Developer', description: 'React, Node.js, MongoDB, JavaScript, HTML, CSS' },
        { id: 4, title: 'DevOps Engineer', description: 'AWS, Docker, Kubernetes, Jenkins, CI/CD, Linux' },
        { id: 5, title: 'Backend Developer', description: 'Python, Django, Flask, PostgreSQL, REST APIs, Git' },
        { id: 6, title: 'Frontend Developer', description: 'React, JavaScript, HTML, CSS, Redux, TypeScript' },
        { id: 7, title: 'Cloud Engineer', description: 'AWS, Azure, GCP, Terraform, Docker, Kubernetes' },
        { id: 8, title: 'HR Generalist', description: 'Recruitment, Employee Relations, HR policies, Onboarding' },
        { id: 9, title: 'Project Manager', description: 'Agile, Scrum, Leadership, Communication, JIRA' },
        { id: 10, title: 'Data Analyst', description: 'SQL, Excel, Tableau, Python, Data Visualization' }
      ];

      const matches = [];
      for (const job of jobs) {
        try {
          const matchRes = await axios.post(`${AI_API_URL}/predict/match`, {
            resume_text: text,
            job_description: job.description,
            job_title: job.title
          });
          matches.push({
            ...job,
            match_score: matchRes.data.match_score,
            match_level: matchRes.data.match_level,
            matching_skills: matchRes.data.matching_skills || 0,
            total_skills: matchRes.data.total_job_skills || 0,
            resume_skills: matchRes.data.resume_skills || [],
            job_skills: matchRes.data.job_skills || []
          });
        } catch (err) {
          console.error(`Error matching ${job.title}:`, err);
        }
      }
      setRecommendations(matches.sort((a, b) => b.match_score - a.match_score));
    } catch (error) {
      console.error('Analysis failed:', error);
    }
    setLoading(false);
  };

  const getMatchColor = (score) => {
    if (score >= 70) return '#28a745';
    if (score >= 50) return '#17a2b8';
    if (score >= 30) return '#ffc107';
    return '#dc3545';
  };

  const getMatchText = (score) => {
    if (score >= 70) return 'Excellent Match';
    if (score >= 50) return 'Good Match';
    if (score >= 30) return 'Fair Match';
    return 'Poor Match';
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1>🤖 AI Career Dashboard</h1>

      {/* AI Status */}
      <div style={{
        padding: '10px',
        borderRadius: '5px',
        marginBottom: '20px',
        background: aiStatus === 'online' ? '#d4edda' : '#f8d7da',
        color: aiStatus === 'online' ? '#155724' : '#721c24'
      }}>
        {aiStatus === 'online' ? '✅ AI Service Connected' : '⚠️ AI Service Offline - Run python predict_api.py'}
      </div>

      {/* Loading State */}
      {loading && (
        <div style={{ textAlign: 'center', padding: '50px' }}>
          <p>🤖 AI is analyzing your resume...</p>
        </div>
      )}

      {/* Resume Category - Only show if resume exists */}
      {!loading && resumeCategory && (
        <div style={{
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          color: 'white',
          padding: '20px',
          borderRadius: '10px',
          marginBottom: '20px',
          textAlign: 'center'
        }}>
          <h2>📊 Your Predicted Career Path</h2>
          <div style={{ fontSize: '32px', fontWeight: 'bold', marginTop: '10px' }}>
            {resumeCategory}
          </div>
          <p style={{ marginTop: '10px' }}>
            Based on your resume, AI predicts you're best suited for {resumeCategory} roles
          </p>
        </div>
      )}

      {/* Job Recommendations */}
      <h2>🎯 Recommended Jobs For You</h2>
      
      {!loading && !resumeCategory && (
        <div style={{ textAlign: 'center', padding: '50px', background: '#f8f9fa', borderRadius: '10px' }}>
          <p>📄 No resume found. Please upload a resume first!</p>
          <p style={{ fontSize: '12px', color: '#666' }}>
            Go to <strong>Upload Resume</strong> page and paste your resume.
          </p>
        </div>
      )}

      {!loading && recommendations.length > 0 ? (
        <div style={{ display: 'grid', gap: '15px' }}>
          {recommendations.map((job) => (
            <div key={job.id} style={{
              border: `2px solid ${getMatchColor(job.match_score)}`,
              borderRadius: '10px',
              padding: '15px',
              cursor: 'pointer',
              transition: 'transform 0.2s',
              background: 'white'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap' }}>
                <h3 style={{ margin: 0 }}>{job.title}</h3>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontSize: '28px', fontWeight: 'bold', color: getMatchColor(job.match_score) }}>
                    {job.match_score}%
                  </div>
                  <div style={{ fontSize: '12px', color: '#666' }}>Match Score</div>
                </div>
              </div>
              
              <div style={{ marginTop: '10px' }}>
                <span style={{
                  display: 'inline-block',
                  padding: '5px 10px',
                  borderRadius: '20px',
                  fontSize: '12px',
                  background: getMatchColor(job.match_score) + '20',
                  color: getMatchColor(job.match_score)
                }}>
                  {getMatchText(job.match_score)}
                </span>
                {job.matching_skills > 0 && (
                  <span style={{ marginLeft: '10px', fontSize: '12px', color: '#666' }}>
                    🎯 {job.matching_skills}/{job.total_skills} skills match
                  </span>
                )}
              </div>
              
              <p style={{ marginTop: '10px', color: '#666', fontSize: '14px' }}>
                {job.description}
              </p>

              {/* Show matching skills if available */}
              {job.matching_skills > 0 && job.resume_skills && (
                <div style={{ marginTop: '10px' }}>
                  <div style={{ fontSize: '12px', fontWeight: 'bold', marginBottom: '5px' }}>
                    ✅ Your matching skills:
                  </div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px' }}>
                    {job.resume_skills.slice(0, 5).map((skill, i) => (
                      <span key={i} style={{
                        padding: '2px 8px',
                        background: '#d4edda',
                        color: '#155724',
                        borderRadius: '15px',
                        fontSize: '11px'
                      }}>
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      ) : !loading && resumeCategory && recommendations.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '50px', background: '#f8f9fa', borderRadius: '10px' }}>
          <p>🔄 Loading recommendations...</p>
        </div>
      ) : null}

      {/* Refresh Button - Only show if resume exists */}
      {resumeCategory && (
        <button 
          onClick={() => resumeText && analyzeResume(resumeText)}
          disabled={loading}
          style={{
            marginTop: '20px',
            padding: '10px 20px',
            background: '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: loading ? 'not-allowed' : 'pointer',
            opacity: loading ? 0.6 : 1
          }}
        >
          {loading ? '🤖 Analyzing...' : '🔄 Refresh Recommendations'}
        </button>
      )}
    </div>
  );
};

export default AIDashboard;
